const ListActiveIssuedKeyIDsBounded = `-- name: ListActiveIssuedKeyIDsBounded :many
SELECT key_id FROM issued_api_keys
WHERE nid = ?1 AND status = ?2
ORDER BY key_id
LIMIT ?3
`

// Returns up to sqlc.arg(batch_limit) active issued API key IDs for the network.
// Used for cap enforcement (quota.api_keys_max). The query is bounded;
// callers count the returned rows. Never scans an unbounded set.
func (q *Queries) ListActiveIssuedKeyIDsBounded(ctx context.Context, nID uuid.UUID, activeStatus int32, batchLimit int64) ([]string, error) {
	rows, err := q.query(ctx, q.listActiveIssuedKeyIDsBoundedStmt, ListActiveIssuedKeyIDsBounded, nID, activeStatus, batchLimit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []string{}
	for rows.Next() {
		var key_id string
		if err := rows.Scan(&key_id); err != nil {
			return nil, err
		}
		items = append(items, key_id)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const ListImportedAPIKeys = `-- name: ListImportedAPIKeys :many
SELECT nid, key_id, name, actor_id, scopes, status, metadata, last_used_at, expires_at, created_at, updated_at, rate_limit_quota, rate_limit_window, revocation_reason, revocation_reason_text, allowed_cidrs, request_id, visibility
FROM imported_api_keys
WHERE nid = ?1
  AND (?2 IS NULL OR actor_id = ?2)
  AND (?3 IS NULL OR status = ?3)
  AND (?4 IS NULL OR key_id < ?4)
ORDER BY key_id DESC
LIMIT ?5
`

type ListImportedAPIKeysParams struct {
	NID         uuid.UUID   `db:"nid" json:"nid"`
	ActorID     interface{} `db:"actor_id" json:"actor_id"`
	Status      interface{} `db:"status" json:"status"`
	CursorKeyID interface{} `db:"cursor_key_id" json:"cursor_key_id"`
	PageLimit   int64       `db:"page_limit" json:"page_limit"`
}

// Cursor-based pagination using primary key (key_id)
// Pass NULL for cursor_key_id to start from the beginning
// Note: Imported keys use hash IDs (not time-sortable), so order is deterministic but not chronological
func (q *Queries) ListImportedAPIKeys(ctx context.Context, arg ListImportedAPIKeysParams) ([]ImportedApiKey, error) {
	rows, err := q.query(ctx, q.listImportedAPIKeysStmt, ListImportedAPIKeys,
		arg.NID,
		arg.ActorID,
		arg.Status,
		arg.CursorKeyID,
		arg.PageLimit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ImportedApiKey{}
	for rows.Next() {
		var i ImportedApiKey
		if err := rows.Scan(
			&i.NID,
			&i.KeyID,
			&i.Name,
			&i.ActorID,
			&i.Scopes,
			&i.Status,
			&i.Metadata,
			&i.LastUsedAt,
			&i.ExpiresAt,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.RateLimitQuota,
			&i.RateLimitWindow,
			&i.RevocationReason,
			&i.RevocationReasonText,
			&i.AllowedCidrs,
			&i.RequestID,
			&i.Visibility,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

